INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (1,'1','<p>Konsistensi dengan hasil analisis SWOT dan/atau analisis lain serta&nbsp;<br>rencana pengembangan ke depan.</p>','kondisi eksternal UPPS',1,'2026-03-15 12:51:12','2026-03-17 12:13:21');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (2,'2','<p>Keserbacakupan informasi dalam profil dan konsistensi antara profil&nbsp;<br>dengan data dan informasi yang disampaikan pada masing-masing&nbsp;<br>kriteria, serta menunjukkan iklim yang kondusif untuk pengembangan&nbsp;<br>dan reputasi sebagai rujukan di bidang keilmuannya.</p>','Profil UPPS',1,'2026-03-15 13:42:01','2026-03-17 12:13:43');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (3,'3','<p>&nbsp;Kesesuaian Visi, Misi, Tujuan dan Strategi (VMTS) Unit Pengelola Program Studi (UPPS) terhadap VMTS Perguruan Tinggi (PT) dan visi keilmuan Program Studi (PS) yang dikelolanya.&nbsp;</p>','Kesesuain VMTS',1,'2026-04-12 04:38:22','2026-04-12 04:38:22');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (4,'4','<p> Mekanisme dan keterlibatan pemangku kepentingan dalam penyusunan VMTS UPPS. </p>','Mekanisme penyusunan  VMTS',1,'2026-04-12 04:38:55','2026-04-12 04:38:58');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (5,'5','<p>&nbsp;Strategi pencapaian tujuan disusun berdasarkan analisis yang sistematis, serta pada pelaksanaannya dilakukan pemantauan dan evaluasi yang ditindaklanjuti.&nbsp;</p>','Strategi pencapaian',1,'2026-04-12 04:39:46','2026-04-12 04:39:46');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (6,'6A','<p>&nbsp;A. Kelengkapan struktur organisasi dan keefektifan penyelenggaraan organisasi.&nbsp;</p>','kelengkapan struktur  organisasi',1,'2026-04-12 04:40:11','2026-04-12 04:40:11');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (9,'6B','<p>B. Perwujudan good governance dan pemenuhan lima pilar sistem tata pamong, yang mencakup:&nbsp;</p><p>1) perencanaan,</p><p>2) pengorganisasian,&nbsp;</p><p>3) penempatan personel,&nbsp;</p><p>4) pelaksanaan,&nbsp;</p><p>5) pengendalian dan pengawasan, dan&nbsp;</p><p>6) pelaporan yang menjadi dasar tindak lanjut.&nbsp;</p>','Perwujudan good  governance',1,'2026-04-12 08:08:59','2026-04-12 08:20:34');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (10,'7A','<p>&nbsp;A. Komitmen pimpinan UPPS.&nbsp;</p>','Komitmen pimpinan UPPS',1,'2026-04-12 08:22:10','2026-04-12 12:40:40');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (12,'7B','<p>&nbsp;B. Kapabilitas pimpinan UPPS, mencakup aspek:&nbsp;</p><p>1) perencanaan,&nbsp;</p><p>2) pengorganisasian,&nbsp;</p><p>3) penempatan personel,&nbsp;</p><p>4) pelaksanaan,&nbsp;</p><p>5) pengendalian dan pengawasan, dan&nbsp;</p><p>6) pelaporan yang menjadi dasar tindak lanjut.&nbsp;</p>','Kapabilitas pimpinan UPPS',1,'2026-04-12 12:41:24','2026-04-12 12:41:24');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (13,'8','<p>Mutu, manfaat, kepuasan dan keberlanjutan kerjasama pendidikan, penelitian dan PkM yang relevan dengan program studi.&nbsp;</p><p>UPPS memiliki bukti yang sahih terkait kerjasama yang ada telah memenuhi 3 aspek berikut:&nbsp;</p><p>1) memberikan manfaat bagi program studi dalam pemenuhan proses pembelajaran, penelitian, PkM.&nbsp;</p><p>2) memberikan peningkatan kinerja tridharma dan fasilitas pendukung program studi.&nbsp;</p><p>3) memberikan kepuasan kepada mitra industri dan mitra kerjasama lainnya, serta menjamin keberlanjutan kerjasama dan hasilnya&nbsp;</p>','Keberlanjutan kerjasama',1,'2026-04-15 15:38:50','2026-04-15 16:24:39');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (14,'9A','<p>&nbsp;A. Kerjasama pendidikan, penelitian, dan PkM yang relevan dengan program studi dan dikelola oleh UPPS dalam 3 tahun terakhir.&nbsp;</p>','Jumlah kerjasama',1,'2026-04-15 17:24:35','2026-04-15 17:24:35');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (15,'9B','<p>&nbsp;B. Kerjasama tingkat internasional, nasional, wilayah/lokal yang relevan dengan program studi dan dikelola oleh UPPS dalam 3 tahun terakhir.&nbsp;</p>','tingkat kerjasama',1,'2026-04-15 17:24:53','2026-04-15 17:24:53');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (16,'10','<p>Pelampauan SN-DIKTI yang ditetapkan dengan indikator kinerja tambahan yang berlaku di UPPS berdasarkan standar pendidikan tinggi yang ditetapkan perguruan tinggi pada tiap kriteria.&nbsp;</p>','pelampauan SNDIKTI',1,'2026-04-15 17:25:13','2026-04-15 17:25:13');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (17,'11','<p>&nbsp;Analisis keberhasilan dan/atau ketidakberhasilan pencapaian kinerja UPPS yang telah ditetapkan di tiap kriteria memenuhi 2 aspek sebagai berikut: 1) capaian kinerja diukur dengan metoda yang tepat, dan hasilnya dianalisis serta dievaluasi, dan 2) analisis terhadap capaian kinerja mencakup identifikasi akar masalah, faktor pendukung keberhasilan dan faktor penghambat ketercapaian standard, dan deskripsi singkat tindak lanjut yang akan dilakukan.&nbsp;</p>','analisis capaian kinerja',1,'2026-04-15 17:25:31','2026-04-15 17:25:31');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (18,'12','<p>&nbsp;Keterlaksanaan Sistem Penjaminan MutuInternal (akademik dan nonakademik) yang dibuktikan dengan keberadaan 5 aspek: 1) dokumen legal pembentukan unsur pelaksana penjaminan mutu. 2) ketersediaan dokumen mutu: kebijakan SPMI, manual SPMI, standar SPMI, dan formulir SPMI. 3) terlaksananya siklus penjaminan mutu (siklus PPEPP) 4) bukti sahih efektivitas pelaksanaan penjaminan mutu. 5) memiliki external benchmarking dalampeningkatan mutu.&nbsp;</p>','Keterlaksanaan SPMI',1,'2026-04-15 17:25:52','2026-04-15 17:25:52');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (19,'13','<p>&nbsp;Pengukuran kepuasan para pemangku kepentingan(mahasiswa, dosen, tenaga kependidikan, lulusan, pengguna, mitra industri, dan mitra lainnya) terhadap layanan manajemen, yang memenuhi aspekaspek berikut: 1) menggunakan instrumen kepuasan yang sahih, andal, mudah digunakan, 2) dilaksanakan secara berkala, serta datanya terekam secara komprehensif, 3) dianalisis dengan metode yang tepat serta bermanfaat untuk pengambilan keputusan, 4) tingkat kepuasan dan umpan balik ditindaklanjuti untuk perbaikan dan peningkatan mutu luaran secara berkala dan tersistem. 5) dilakukan review terhadap pelaksanaan pengukuran kepuasan dosen dan mahasiswa, serta 6) hasilnya dipublikasikan dan mudah diakses oleh dosen dan mahasiswa&nbsp;</p>','Pengukuran kepuasan pemangku kepentingan',1,'2026-04-15 17:26:20','2026-04-15 17:26:20');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (20,'14','<p>&nbsp;Metoda rekrutmen dan keketatan seleksi.&nbsp;</p>','metode seleksi mahasiswa',1,'2026-04-15 17:26:35','2026-04-15 17:26:35');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (21,'15','<p>&nbsp;A. Peningkatan animo calon mahasiswa.&nbsp;</p><p>&nbsp;B. Mahasiswa asing&nbsp;</p>','animo calon mahasiswa,jumlah mahasiswa asing',1,'2026-04-15 17:27:12','2026-04-15 17:27:12');
INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (22,'16','<p>&nbsp;A. Ketersediaan layanan kemahasiswaan di bidang:&nbsp;</p><p>&nbsp;B. Akses dan mutu layanan kemahasiswaan.&nbsp;</p>','layanan kemahasiswaan,akses dan mutu layanan',1,'2026-04-15 17:28:00','2026-04-15 17:28:00');
