INSERT INTO `standards` (`id`, `nomor`, `deskriptor`, `keywords`, `cycles_id`, `created_at`, `updated_at`) VALUES (37,'31','<p>A. Kualifikasi dan kecukupan tenaga kependidikan berdasarkan jenis pekerjaannya (administrasi, pustakawan, teknisi, dll.) Penilaian kecukupan tidak hanya ditentukan oleh jumlah tenaga kependidikan, namun keberadaan dan pemanfaatan teknologi informasi dan komputer dalam proses administrasi dapat dijadikan pertimbangan untuk menilai efektifitas pekerjaan dan kebutuhan akan tenaga kependidikan.&nbsp;</p><p>&nbsp;B. Kualifikasi dan kecukupan laboran untuk mendukung proses pembelajaran sesuai dengan kebutuhan program studi.&nbsp;</p>','Kuallifikasi tendik,Kualifikasi laboran',1,'2026-04-15 18:18:01','2026-04-15 18:18:01');
